```class Solution {
public:
    char repeatedCharacter(string s) {
        unordered_map<char, int> count;
        for (char c : s) {
            if (count.find(c) != count.end()) {
                return c;
            }
            count[c] = 1;
        }
        return ' ';
    }
};
```
